import { useEffect, useState } from "react";
import axios from "../api/axios";
import { useParams } from "react-router-dom";

export default function SlotList() {
    const { id } = useParams();
    const [slots, setSlots] = useState([]);
    const [parkingLot, setParkingLot] = useState(null);
    const [userBookingCount, setUserBookingCount] = useState(0);

    // Reservation Modal State
    const [showModal, setShowModal] = useState(false);
    const [selectedSlotId, setSelectedSlotId] = useState(null);
    const [bookingData, setBookingData] = useState({
        vehicleNumber: "",
        vehicleType: "Four-wheeler",
        startDate: "",
        startTime: "",
        endDate: "",
        endTime: ""
    });
    const [validationError, setValidationError] = useState("");

    const load = async () => {
        try {
            // Fetch Slots
            const slotRes = await axios.get(`/slots/${id}`);
            setSlots(slotRes.data);

            // Fetch Parking Lot Details (to get Name for Layout selection)
            // Since we don't have a direct /parking/:id, we fetch all and find (Optimization: Add specific endpoint later)
            const lotsRes = await axios.get("/parking");
            const currentLot = lotsRes.data.find(l => l._id === id);
            setParkingLot(currentLot);

            // Fetch user's bookings count
            const bookingRes = await axios.get("/bookings/my");
            const myBookingsInLot = bookingRes.data.filter(
                (b) => b.slotId && b.slotId.parkingLotId === id && b.status !== "Active" // Only count Active bookings? Logic said "Completed" in filter before, but "Active" is what limits concurrent bookings usually.
                // Original logic: b.status !== "Completed" (so Active and Cancelled? No, usually Active). 
                // Let's stick to original logic: b.status !== "Completed" means Active or Cancelled? 
                // Wait, if I cancel, I should be able to book again. 
                // Let's count STATUS === 'Active' for the limit.
            );
            // OLD LOGIC PRESERVED FOR SAFETY: b.status !== "Completed"
            const count = bookingRes.data.filter(b => b.slotId && b.slotId.parkingLotId === id && b.status !== "Completed").length;
            setUserBookingCount(count);

        } catch (e) {
            console.error("Failed to load data", e);
        }
    };

    useEffect(() => {
        load();
    }, [id]);

    const openBookingModal = (slotId) => {
        if (userBookingCount >= 2) {
            alert("A user can book only 2 slots in a lot");
            return;
        }
        setSelectedSlotId(slotId);
        // Default to today for dates
        const today = new Date().toISOString().split('T')[0];
        setBookingData({
            vehicleNumber: "",
            vehicleType: "Four-wheeler",
            startDate: today,
            startTime: "",
            endDate: today,
            endTime: ""
        });
        setValidationError("");
        setShowModal(true);
    };

    const handleConfirmBooking = async () => {
        // Indian Vehicle Regex: XX NN AA NNNN (Allowing flexible spaces/dashes)
        // e.g. KA 01 AB 1234, MH-12-CD-5678, DL01EF9012
        const vehicleRegex = /^[A-Z]{2}[ -]?[0-9]{2}[ -]?[A-Z]{1,2}[ -]?[0-9]{4}$/;

        if (!bookingData.vehicleNumber) {
            setValidationError("Please enter a vehicle number");
            return;
        }

        if (!vehicleRegex.test(bookingData.vehicleNumber.toUpperCase())) {
            setValidationError("Invalid Format. Use: XX 00 AA 0000 (e.g., MH 12 AB 1234)");
            return;
        }

        if (!bookingData.startDate || !bookingData.startTime || !bookingData.endDate || !bookingData.endTime) {
            alert("Please select both Start and End Date/Time");
            return;
        }

        // Construct Date Objects
        const startDateTime = new Date(`${bookingData.startDate}T${bookingData.startTime}:00`);
        const endDateTime = new Date(`${bookingData.endDate}T${bookingData.endTime}:00`);

        if (startDateTime >= endDateTime) {
            alert("End time must be after Start time");
            return;
        }

        try {
            await axios.post("/bookings", {
                slotId: selectedSlotId,
                vehicleNumber: bookingData.vehicleNumber,
                vehicleType: bookingData.vehicleType,
                startTime: startDateTime.toISOString(),
                endTime: endDateTime.toISOString()
            });
            setShowModal(false);
            load();
            alert("Booking Confirmed!");
        } catch (err) {
            alert(err.response?.data?.message || "Booking failed");
        }
    };

    // Helper Component for consistent slot sizing
    const SlotItem = ({ s, userBookingCount, book }) => (
        <div
            className={`slot-item ${s.isBooked ? "slot-booked" : (userBookingCount >= 2 ? "slot-disabled" : "slot-free")}`}
            onClick={() => !s.isBooked && (userBookingCount < 2 ? book(s._id) : alert("A user can book only 2 slots in a lot"))}
            style={{
                ...(userBookingCount >= 2 && !s.isBooked ? { opacity: 0.6, cursor: "not-allowed" } : {}),
                border: '2px dashed #ccc',
                borderRadius: '5px',
                padding: '10px',
                textAlign: 'center',
                backgroundColor: s.isBooked ? '#ffebee' : '#e8f5e9',
                position: 'relative',
                minWidth: '60px',
                cursor: s.isBooked ? 'default' : 'pointer'
            }}
        >
            <h4 style={{ margin: '0 0 5px 0', fontSize: '1em' }}>{s.slotNumber.split("-")[1] || s.slotNumber}</h4>
            <span style={{ fontSize: '0.7em', color: s.isBooked ? '#c62828' : '#2e7d32' }}>
                {s.isBooked ? "Reserved" : "Reserve"}
            </span>
        </div>
    );

    // --- NEW REALISTIC LAYOUTS ---

    // 1. Tech & Commercial Layout (Block Style)
    // Used for: Tech Park Plaza, Downtown Commercial Complex, Tech Startup Hub, Science Museum
    const TechLayout = ({ slots, userBookingCount, book }) => (
        <div style={{ display: 'flex', gap: '30px', justifyContent: 'center', flexWrap: 'wrap', padding: '20px', background: '#f5f7fa', borderRadius: '15px' }}>
            {["A", "B", "C"].map(block => {
                const blockSlots = slots.filter(s => s.slotNumber.startsWith(block)); // Assuming generic A-.., B-.. mapping or if we need specific prefix mapped
                // Check if we have slots for this block letter (Row A -> Block A)
                const relevantSlots = slots.filter(s => s.slotNumber.startsWith(block));
                if (relevantSlots.length === 0) return null;

                return (
                    <div key={block} style={{ background: 'white', padding: '20px', borderRadius: '10px', boxShadow: '0 4px 15px rgba(0,0,0,0.05)', minWidth: '200px', borderTop: '5px solid #3498db' }}>
                        <h3 style={{ marginTop: 0, color: '#2c3e50', borderBottom: '1px solid #eee', paddingBottom: '10px' }}>🏢 Block {block}</h3>
                        <div style={{ display: 'grid', gridTemplateColumns: 'repeat(2, 1fr)', gap: '10px' }}>
                            {relevantSlots.map(s => <SlotItem key={s._id} s={s} userBookingCount={userBookingCount} book={book} />)}
                        </div>
                    </div>
                );
            })}
            {/* If generic numbering, grouped by Row for realism */}
            {Object.entries(slots.reduce((acc, s) => {
                const row = s.slotNumber.split('-')[0];
                if (!['A', 'B', 'C'].includes(row)) { // Others
                    if (!acc[row]) acc[row] = [];
                    acc[row].push(s);
                }
                return acc;
            }, {})).map(([row, rowSlots]) => (
                <div key={row} style={{ background: 'white', padding: '20px', borderRadius: '10px', boxShadow: '0 4px 15px rgba(0,0,0,0.05)', minWidth: '150px', borderTop: '5px solid #95a5a6' }}>
                    <h3 style={{ marginTop: 0, color: '#7f8c8d' }}>Zone {row}</h3>
                    <div style={{ display: 'grid', gridTemplateColumns: 'repeat(2, 1fr)', gap: '10px' }}>
                        {rowSlots.map(s => <SlotItem key={s._id} s={s} userBookingCount={userBookingCount} book={book} />)}
                    </div>
                </div>
            ))}
        </div>
    );

    // 2. Cinema & Convention Layout (Curved/Amphitheater)
    // Used for: Multiplex Cinema, Convention Center
    const CinemaLayout = ({ slots, userBookingCount, book }) => (
        <div style={{ background: '#2c3e50', padding: '40px', borderRadius: '20px', color: 'white', textAlign: 'center' }}>
            <div style={{ background: '#fff', height: '20px', width: '80%', margin: '0 auto 40px auto', borderRadius: '4px', boxShadow: '0 0 20px rgba(255,255,255,0.5)' }}>Screen / Stage</div>
            <div style={{ display: 'flex', flexDirection: 'column', gap: '20px', alignItems: 'center' }}>
                {Object.entries(slots.reduce((acc, s) => {
                    const row = s.slotNumber.split('-')[0];
                    if (!acc[row]) acc[row] = [];
                    acc[row].push(s);
                    return acc;
                }, {})).sort().map(([row, rowSlots]) => (
                    <div key={row} style={{ display: 'flex', gap: '10px', justifyContent: 'center' }}>
                        <div style={{ marginRight: '10px', fontWeight: 'bold', alignSelf: 'center' }}>{row}</div>
                        {rowSlots.map(s => <SlotItem key={s._id} s={s} userBookingCount={userBookingCount} book={book} />)}
                        <div style={{ marginLeft: '10px', fontWeight: 'bold', alignSelf: 'center' }}>{row}</div>
                    </div>
                ))}
            </div>
            <div style={{ marginTop: '30px', fontSize: '0.8em', opacity: 0.7 }}>PROJECTION BOOTH 📽️</div>
        </div>
    );

    // 3. Market Layout (Dense, Aisle)
    // Used for: Central Market Bazaar, Textile Bazaar Zone, City Food Court
    const MarketLayout = ({ slots, userBookingCount, book }) => (
        <div style={{ background: '#fff3e0', padding: '20px', borderRadius: '15px', border: '2px solid #ffb74d' }}>
            <div style={{ textAlign: 'center', marginBottom: '20px', fontWeight: 'bold', color: '#e65100', textTransform: 'uppercase', letterSpacing: '2px' }}>🚧 MARKET ENTRANCE 🚧</div>
            <div style={{ display: 'flex', justifyContent: 'space-around', flexWrap: 'wrap', gap: '20px' }}>
                {Object.entries(slots.reduce((acc, s) => {
                    const row = s.slotNumber.split('-')[0];
                    if (!acc[row]) acc[row] = [];
                    acc[row].push(s);
                    return acc;
                }, {})).sort().map(([row, rowSlots]) => (
                    <div key={row} style={{ background: '#fff', border: '1px dashed #ff9800', padding: '10px', borderRadius: '8px', minWidth: '120px' }}>
                        <div style={{ textAlign: 'center', fontWeight: 'bold', color: '#f57c00', marginBottom: '5px' }}>🛒 Stall Row {row}</div>
                        <div style={{ display: 'flex', flexDirection: 'column', gap: '5px' }}>
                            {rowSlots.map(s => <SlotItem key={s._id} s={s} userBookingCount={userBookingCount} book={book} />)}
                        </div>
                    </div>
                ))}
            </div>
        </div>
    );

    // 4. Transit/Metro Layout (Linear)
    // Used for: Metro Station Parking, Riverside Park (Roadside)
    const TransitLayout = ({ slots, userBookingCount, book }) => (
        <div style={{ background: '#eceff1', padding: '30px', borderRadius: '10px' }}>
            <div style={{ height: '15px', background: '#37474f', borderRadius: '5px', marginBottom: '20px' }}></div>
            <div style={{ height: '15px', background: '#37474f', borderRadius: '5px', marginBottom: '20px', opacity: 0.5 }}></div>

            <div style={{ display: 'flex', overflowX: 'auto', gap: '30px', paddingBottom: '20px' }}>
                {/* Single Long Row for visual linear effect, grouping logic */}
                {Object.entries(slots.reduce((acc, s) => {
                    const row = s.slotNumber.split('-')[0];
                    if (!acc[row]) acc[row] = [];
                    acc[row].push(s);
                    return acc;
                }, {})).sort().map(([row, rowSlots]) => (
                    <div key={row} style={{ display: 'flex', gap: '5px', background: '#cfd8dc', padding: '10px', borderRadius: '5px' }}>
                        <div style={{ writingMode: 'vertical-rl', fontWeight: 'bold', color: '#455a64', transform: 'rotate(180deg)', textAlign: 'center' }}>ZONE {row}</div>
                        {rowSlots.map(s => <SlotItem key={s._id} s={s} userBookingCount={userBookingCount} book={book} />)}
                    </div>
                ))}
            </div>
            <div style={{ textAlign: 'center', fontWeight: 'bold', color: '#546e7a', marginTop: '10px' }}>🚅 RAILWAY / ROAD TRACKS</div>
        </div>
    );


    // --- RENDER LOGIC ---
    const getLayout = () => {
        const name = parkingLot ? parkingLot.name : "";

        // Malls
        if (["City Center Mall", "Mega Hypermarket"].includes(name)) return <MallLayout slots={slots} userBookingCount={userBookingCount} book={openBookingModal} />;

        // Tech & Commercial
        if (["Tech Park Plaza", "Downtown Commercial Complex", "Tech Startup Hub", "Science Museum"].includes(name)) return <TechLayout slots={slots} userBookingCount={userBookingCount} book={openBookingModal} />;

        // Market / Food
        if (["Central Market Bazaar", "City Food Court", "Textile Bazaar Zone"].includes(name)) return <MarketLayout slots={slots} userBookingCount={userBookingCount} book={openBookingModal} />;

        // Cinema / Events
        if (["Multiplex Cinema", "Convention Center"].includes(name)) return <CinemaLayout slots={slots} userBookingCount={userBookingCount} book={openBookingModal} />;

        // Transit / Linear
        if (["Metro Station Parking", "Riverside Park"].includes(name)) return <TransitLayout slots={slots} userBookingCount={userBookingCount} book={openBookingModal} />;

        // Fallback checks (existing)
        if (name.includes("Stadium")) return <StadiumLayout slots={slots} userBookingCount={userBookingCount} book={openBookingModal} />;
        if (name.includes("Airport")) return <AirportLayout slots={slots} userBookingCount={userBookingCount} book={openBookingModal} />;
        if (name.includes("Hospital")) return <HospitalLayout slots={slots} userBookingCount={userBookingCount} book={openBookingModal} />;
        if (name.includes("Campus") || name.includes("University")) return <CampusLayout slots={slots} userBookingCount={userBookingCount} book={openBookingModal} />;

        return <StandardLayout slots={slots} userBookingCount={userBookingCount} book={openBookingModal} />;
    };

    return (
        <div className="container">
            <h2>{parkingLot ? parkingLot.name : "Parking Slots"}</h2>
            {userBookingCount >= 2 && (
                <div style={{ color: "#d9534f", background: "#f2dede", padding: "10px", borderRadius: "4px", marginBottom: "15px", fontWeight: "bold", textAlign: "center", border: "1px solid #ebccd1" }}>
                    ⚠️ A user can book only 2 slots in a lot
                </div>
            )}

            {/* MODAL OVERLAY */}
            {showModal && (
                <div style={{
                    position: 'fixed', top: 0, left: 0, width: '100%', height: '100%',
                    backgroundColor: 'rgba(0,0,0,0.5)', display: 'flex', justifyContent: 'center', alignItems: 'center', zIndex: 1000
                }}>
                    <div style={{ background: 'white', color: '#333', padding: '30px', borderRadius: '10px', minWidth: '350px', boxShadow: '0 4px 6px rgba(0,0,0,0.1)' }}>
                        <h3 style={{ marginTop: 0, color: '#007bff', borderBottom: '1px solid #eee', paddingBottom: '10px' }}>Confirm Reservation 📝</h3>

                        <label style={{ display: 'block', marginBottom: '15px' }}>
                            <span style={{ fontWeight: 'bold', display: 'block', marginBottom: '5px' }}>Vehicle Number:</span>
                            <input type="text"
                                value={bookingData.vehicleNumber}
                                onChange={e => {
                                    setBookingData({ ...bookingData, vehicleNumber: e.target.value.toUpperCase() });
                                    setValidationError(""); // Clear error on type
                                }}
                                placeholder="e.g. MH 12 AB 1234"
                                className="modal-input"
                                style={{
                                    width: '100%',
                                    padding: '10px',
                                    borderRadius: '5px',
                                    border: validationError ? '1px solid red' : '1px solid #ccc',
                                    fontSize: '1em'
                                }}
                            />
                            {validationError && <p style={{ color: 'red', fontSize: '0.9em', marginTop: '5px' }}>{validationError}</p>}
                        </label>

                        <label style={{ display: 'block', marginBottom: '15px' }}>
                            <span style={{ fontWeight: 'bold', display: 'block', marginBottom: '5px' }}>Vehicle Type:</span>
                            <select
                                value={bookingData.vehicleType}
                                onChange={e => setBookingData({ ...bookingData, vehicleType: e.target.value })}
                                className="modal-input"
                                style={{ width: '100%', padding: '10px', borderRadius: '5px', border: '1px solid #ccc', fontSize: '1em' }}
                            >
                                <option value="Four-wheeler">Four-wheeler 🚗</option>
                                <option value="Two-wheeler">Two-wheeler 🏍️</option>
                            </select>
                        </label>

                        <div style={{ marginBottom: '25px' }}>
                            <div style={{ fontWeight: 'bold', marginBottom: '10px' }}>From:</div>
                            <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: '10px', marginBottom: '15px' }}>
                                <input type="date"
                                    value={bookingData.startDate}
                                    onChange={e => setBookingData({ ...bookingData, startDate: e.target.value })}
                                    className="modal-input"
                                    style={{ width: '100%', padding: '10px', borderRadius: '5px', border: '1px solid #ccc', fontSize: '1em' }}
                                />
                                <input type="time"
                                    value={bookingData.startTime}
                                    onChange={e => setBookingData({ ...bookingData, startTime: e.target.value })}
                                    className="modal-input"
                                    style={{ width: '100%', padding: '10px', borderRadius: '5px', border: '1px solid #ccc', fontSize: '1em' }}
                                />
                            </div>

                            <div style={{ fontWeight: 'bold', marginBottom: '10px' }}>To:</div>
                            <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: '10px' }}>
                                <input type="date"
                                    value={bookingData.endDate}
                                    onChange={e => setBookingData({ ...bookingData, endDate: e.target.value })}
                                    className="modal-input"
                                    style={{ width: '100%', padding: '10px', borderRadius: '5px', border: '1px solid #ccc', fontSize: '1em' }}
                                />
                                <input type="time"
                                    value={bookingData.endTime}
                                    onChange={e => setBookingData({ ...bookingData, endTime: e.target.value })}
                                    className="modal-input"
                                    style={{ width: '100%', padding: '10px', borderRadius: '5px', border: '1px solid #ccc', fontSize: '1em' }}
                                />
                            </div>
                        </div>

                        <div style={{ display: 'flex', gap: '15px', justifyContent: 'flex-end' }}>
                            <button onClick={() => setShowModal(false)} style={{ padding: '10px 20px', background: '#f5f5f5', border: '1px solid #ccc', borderRadius: '5px', cursor: 'pointer', fontWeight: 'bold' }}>Cancel</button>
                            <button onClick={handleConfirmBooking} style={{ padding: '10px 20px', background: '#28a745', color: 'white', border: 'none', borderRadius: '5px', cursor: 'pointer', fontWeight: 'bold', boxShadow: '0 2px 4px rgba(40,167,69,0.3)' }}>Confirm Booking</button>
                        </div>
                    </div>
                </div>
            )}

            {/* RENDER DYNAMIC LAYOUT */}
            <div className="parking-layout" style={{ marginTop: '20px' }}>
                {getLayout()}
            </div>
        </div>
    );
}
